window.BIBLE["SongofSolomon"] = {"1":{"chapter":"1","title":"Song of Solomon 1","verses":{"1":{"text":"The song of songs, which is Solomon’s.","ref":"Song of Solomon 1:1","synthesized":"The song of songs, which is Solomon’s.","sources":{"KJV":{"text":"The song of songs, which is Solomon’s."}},"definableWords":[],"peopleInVerse":["Solomon"]},"2":{"text":"Let him kiss me with the kisses of his mouth: for thy love is better than wine.","ref":"Song of Solomon 1:2","synthesized":"Let him kiss me with the kisses of his mouth: for thy love is better than wine.","sources":{"KJV":{"text":"Let him kiss me with the kisses of his mouth: for thy love is better than wine."}},"definableWords":["love"],"peopleInVerse":[]},"3":{"text":"Because of the savour of thy good ointments thy name is as ointment poured forth, therefore do the virgins love thee.","ref":"Song of Solomon 1:3","synthesized":"Because of the savour of thy good ointments thy name is as ointment poured forth, therefore do the virgins love thee.","sources":{"KJV":{"text":"Because of the savour of thy good ointments thy name is as ointment poured forth, therefore do the virgins love thee."}},"definableWords":["good","name","love"],"peopleInVerse":[]},"4":{"text":"Draw me, we will run after thee: the king hath brought me into his chambers: we will be glad and rejoice in thee, we will remember thy love more than wine: the upright love thee.","ref":"Song of Solomon 1:4","synthesized":"Draw me, we will run after thee: the king hath brought me into his chambers: we will be glad and rejoice in thee, we will remember thy love more than wine: the upright love thee.","sources":{"KJV":{"text":"Draw me, we will run after thee: the king hath brought me into his chambers: we will be glad and rejoice in thee, we will remember thy love more than wine: the upright love thee."}},"definableWords":["king","remember","love"],"peopleInVerse":[]},"5":{"text":"I am black, but comely, O ye daughters of Jerusalem, as the tents of Kedar, as the curtains of Solomon.","ref":"Song of Solomon 1:5","synthesized":"I am black, but comely, O ye daughters of Jerusalem, as the tents of Kedar, as the curtains of Solomon.","sources":{"KJV":{"text":"I am black, but comely, O ye daughters of Jerusalem, as the tents of Kedar, as the curtains of Solomon."}},"definableWords":["daughters"],"peopleInVerse":["Solomon"]},"6":{"text":"Look not upon me, because I am black, because the sun hath looked upon me: my mother’s children were angry with me; they made me the keeper of the vineyards; but mine own vineyard have I not kept.","ref":"Song of Solomon 1:6","synthesized":"Look not upon me, because I am black, because the sun hath looked upon me: my mother’s children were angry with me; they made me the keeper of the vineyards; but mine own vineyard have I not kept.","sources":{"KJV":{"text":"Look not upon me, because I am black, because the sun hath looked upon me: my mother’s children were angry with me; they made me the keeper of the vineyards; but mine own vineyard have I not kept."}},"definableWords":["mother","made"],"peopleInVerse":[]},"7":{"text":"Tell me, O thou whom my soul loveth, where thou feedest, where thou makest thy flock to rest at noon: for why should I be as one that turneth aside by the flocks of thy companions?","ref":"Song of Solomon 1:7","synthesized":"Tell me, O thou whom my soul loveth, where thou feedest, where thou makest thy flock to rest at noon: for why should I be as one that turneth aside by the flocks of thy companions?","sources":{"KJV":{"text":"Tell me, O thou whom my soul loveth, where thou feedest, where thou makest thy flock to rest at noon: for why should I be as one that turneth aside by the flocks of thy companions?"}},"definableWords":["soul","rest","one"],"peopleInVerse":[]},"8":{"text":"If thou know not, O thou fairest among women, go thy way forth by the footsteps of the flock, and feed thy kids beside the shepherds’ tents.","ref":"Song of Solomon 1:8","synthesized":"If thou know not, O thou fairest among women, go thy way forth by the footsteps of the flock, and feed thy kids beside the shepherds’ tents.","sources":{"KJV":{"text":"If thou know not, O thou fairest among women, go thy way forth by the footsteps of the flock, and feed thy kids beside the shepherds’ tents."}},"definableWords":["women","way"],"peopleInVerse":[]},"9":{"text":"I have compared thee, O my love, to a company of horses in Pharaoh’s chariots.","ref":"Song of Solomon 1:9","synthesized":"I have compared thee, O my love, to a company of horses in Pharaoh’s chariots.","sources":{"KJV":{"text":"I have compared thee, O my love, to a company of horses in Pharaoh’s chariots."}},"definableWords":["love","Pharaoh"],"peopleInVerse":[]},"10":{"text":"Thy cheeks are comely with rows of jewels, thy neck with chains of gold.","ref":"Song of Solomon 1:10","synthesized":"Thy cheeks are comely with rows of jewels, thy neck with chains of gold.","sources":{"KJV":{"text":"Thy cheeks are comely with rows of jewels, thy neck with chains of gold."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"We will make thee borders of gold with studs of silver.","ref":"Song of Solomon 1:11","synthesized":"We will make thee borders of gold with studs of silver.","sources":{"KJV":{"text":"We will make thee borders of gold with studs of silver."}},"definableWords":["make"],"peopleInVerse":[]},"12":{"text":"While the king sitteth at his table, my spikenard sendeth forth the smell thereof.","ref":"Song of Solomon 1:12","synthesized":"While the king sitteth at his table, my spikenard sendeth forth the smell thereof.","sources":{"KJV":{"text":"While the king sitteth at his table, my spikenard sendeth forth the smell thereof."}},"definableWords":["king"],"peopleInVerse":[]},"13":{"text":"A bundle of myrrh is my well-beloved unto me; he shall lie all night betwixt my breasts.","ref":"Song of Solomon 1:13","synthesized":"A bundle of myrrh is my well-beloved unto me; he shall lie all night betwixt my breasts.","sources":{"KJV":{"text":"A bundle of myrrh is my well-beloved unto me; he shall lie all night betwixt my breasts."}},"definableWords":["night"],"peopleInVerse":[]},"14":{"text":"My beloved is unto me as a cluster of camphire in the vineyards of Engedi.","ref":"Song of Solomon 1:14","synthesized":"My beloved is unto me as a cluster of camphire in the vineyards of Engedi.","sources":{"KJV":{"text":"My beloved is unto me as a cluster of camphire in the vineyards of Engedi."}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"Behold, thou art fair, my love; behold, thou art fair; thou hast doves’ eyes.","ref":"Song of Solomon 1:15","synthesized":"Behold, thou art fair, my love; behold, thou art fair; thou hast doves’ eyes.","sources":{"KJV":{"text":"Behold, thou art fair, my love; behold, thou art fair; thou hast doves’ eyes."}},"definableWords":["love"],"peopleInVerse":[]},"16":{"text":"Behold, thou art fair, my beloved, yea, pleasant: also our bed is green.","ref":"Song of Solomon 1:16","synthesized":"Behold, thou art fair, my beloved, yea, pleasant: also our bed is green.","sources":{"KJV":{"text":"Behold, thou art fair, my beloved, yea, pleasant: also our bed is green."}},"definableWords":[],"peopleInVerse":[]},"17":{"text":"The beams of our house are cedar, and our rafters of fir.","ref":"Song of Solomon 1:17","synthesized":"The beams of our house are cedar, and our rafters of fir.","sources":{"KJV":{"text":"The beams of our house are cedar, and our rafters of fir."}},"definableWords":["house"],"peopleInVerse":[]}}},"2":{"chapter":"2","title":"Song of Solomon 2","verses":{"1":{"text":"I am the rose of Sharon, and the lily of the valleys.","ref":"Song of Solomon 2:1","synthesized":"I am the rose of Sharon, and the lily of the valleys.","sources":{"KJV":{"text":"I am the rose of Sharon, and the lily of the valleys."}},"definableWords":[],"peopleInVerse":[]},"2":{"text":"As the lily among thorns, so is my love among the daughters.","ref":"Song of Solomon 2:2","synthesized":"As the lily among thorns, so is my love among the daughters.","sources":{"KJV":{"text":"As the lily among thorns, so is my love among the daughters."}},"definableWords":["love","daughters"],"peopleInVerse":[]},"3":{"text":"As the apple tree among the trees of the wood, so is my beloved among the sons. I sat down under his shadow with great delight, and his fruit was sweet to my taste.","ref":"Song of Solomon 2:3","synthesized":"As the apple tree among the trees of the wood, so is my beloved among the sons. I sat down under his shadow with great delight, and his fruit was sweet to my taste.","sources":{"KJV":{"text":"As the apple tree among the trees of the wood, so is my beloved among the sons. I sat down under his shadow with great delight, and his fruit was sweet to my taste."}},"definableWords":["tree","trees","sons","great"],"peopleInVerse":[]},"4":{"text":"He brought me to the banqueting house, and his banner over me was love.","ref":"Song of Solomon 2:4","synthesized":"He brought me to the banqueting house, and his banner over me was love.","sources":{"KJV":{"text":"He brought me to the banqueting house, and his banner over me was love."}},"definableWords":["house","love"],"peopleInVerse":[]},"5":{"text":"Stay me with flagons, comfort me with apples: for I am sick of love.","ref":"Song of Solomon 2:5","synthesized":"Stay me with flagons, comfort me with apples: for I am sick of love.","sources":{"KJV":{"text":"Stay me with flagons, comfort me with apples: for I am sick of love."}},"definableWords":["love"],"peopleInVerse":[]},"6":{"text":"His left hand is under my head, and his right hand doth embrace me.","ref":"Song of Solomon 2:6","synthesized":"His left hand is under my head, and his right hand doth embrace me.","sources":{"KJV":{"text":"His left hand is under my head, and his right hand doth embrace me."}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"I charge you, O ye daughters of Jerusalem, by the roes, and by the hinds of the field, that ye stir not up, nor awake my love, till he please.","ref":"Song of Solomon 2:7","synthesized":"I charge you, O ye daughters of Jerusalem, by the roes, and by the hinds of the field, that ye stir not up, nor awake my love, till he please.","sources":{"KJV":{"text":"I charge you, O ye daughters of Jerusalem, by the roes, and by the hinds of the field, that ye stir not up, nor awake my love, till he please."}},"definableWords":["charge","daughters","field","love","till"],"peopleInVerse":[]},"8":{"text":"The voice of my beloved! behold, he cometh leaping upon the mountains, skipping upon the hills.","ref":"Song of Solomon 2:8","synthesized":"The voice of my beloved! behold, he cometh leaping upon the mountains, skipping upon the hills.","sources":{"KJV":{"text":"The voice of my beloved! behold, he cometh leaping upon the mountains, skipping upon the hills."}},"definableWords":["voice"],"peopleInVerse":[]},"9":{"text":"My beloved is like a roe or a young hart: behold, he standeth behind our wall, he looketh forth at the windows, shewing himself through the lattice.","ref":"Song of Solomon 2:9","synthesized":"My beloved is like a roe or a young hart: behold, he standeth behind our wall, he looketh forth at the windows, shewing himself through the lattice.","sources":{"KJV":{"text":"My beloved is like a roe or a young hart: behold, he standeth behind our wall, he looketh forth at the windows, shewing himself through the lattice."}},"definableWords":["or"],"peopleInVerse":[]},"10":{"text":"My beloved spake, and said unto me, Rise up, my love, my fair one, and come away.","ref":"Song of Solomon 2:10","synthesized":"My beloved spake, and said unto me, Rise up, my love, my fair one, and come away.","sources":{"KJV":{"text":"My beloved spake, and said unto me, Rise up, my love, my fair one, and come away."}},"definableWords":["love","one"],"peopleInVerse":[]},"11":{"text":"For, lo, the winter is past, the rain is over and gone;","ref":"Song of Solomon 2:11","synthesized":"For, lo, the winter is past, the rain is over and gone;","sources":{"KJV":{"text":"For, lo, the winter is past, the rain is over and gone;"}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"The flowers appear on the earth; the time of the singing of birds is come, and the voice of the turtle is heard in our land;","ref":"Song of Solomon 2:12","synthesized":"The flowers appear on the earth; the time of the singing of birds is come, and the voice of the turtle is heard in our land;","sources":{"KJV":{"text":"The flowers appear on the earth; the time of the singing of birds is come, and the voice of the turtle is heard in our land;"}},"definableWords":["earth","birds","voice","land"],"peopleInVerse":[]},"13":{"text":"The fig tree putteth forth her green figs, and the vines with the tender grape give a good smell. Arise, my love, my fair one, and come away.","ref":"Song of Solomon 2:13","synthesized":"The fig tree putteth forth her green figs, and the vines with the tender grape give a good smell. Arise, my love, my fair one, and come away.","sources":{"KJV":{"text":"The fig tree putteth forth her green figs, and the vines with the tender grape give a good smell. Arise, my love, my fair one, and come away."}},"definableWords":["tree","good","love","one"],"peopleInVerse":[]},"14":{"text":"O my dove, that art in the clefts of the rock, in the secret places of the stairs, let me see thy countenance, let me hear thy voice; for sweet is thy voice, and thy countenance is comely.","ref":"Song of Solomon 2:14","synthesized":"O my dove, that art in the clefts of the rock, in the secret places of the stairs, let me see thy countenance, let me hear thy voice; for sweet is thy voice, and thy countenance is comely.","sources":{"KJV":{"text":"O my dove, that art in the clefts of the rock, in the secret places of the stairs, let me see thy countenance, let me hear thy voice; for sweet is thy voice, and thy countenance is comely."}},"definableWords":["see","voice"],"peopleInVerse":[]},"15":{"text":"Take us the foxes, the little foxes, that spoil the vines: for our vines have tender grapes.","ref":"Song of Solomon 2:15","synthesized":"Take us the foxes, the little foxes, that spoil the vines: for our vines have tender grapes.","sources":{"KJV":{"text":"Take us the foxes, the little foxes, that spoil the vines: for our vines have tender grapes."}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"My beloved is mine, and I am his: he feedeth among the lilies.","ref":"Song of Solomon 2:16","synthesized":"My beloved is mine, and I am his: he feedeth among the lilies.","sources":{"KJV":{"text":"My beloved is mine, and I am his: he feedeth among the lilies."}},"definableWords":[],"peopleInVerse":[]},"17":{"text":"Until the day break, and the shadows flee away, turn, my beloved, and be thou like a roe or a young hart upon the mountains of Bether.","ref":"Song of Solomon 2:17","synthesized":"Until the day break, and the shadows flee away, turn, my beloved, and be thou like a roe or a young hart upon the mountains of Bether.","sources":{"KJV":{"text":"Until the day break, and the shadows flee away, turn, my beloved, and be thou like a roe or a young hart upon the mountains of Bether."}},"definableWords":["day","or"],"peopleInVerse":[]}}},"3":{"chapter":"3","title":"Song of Solomon 3","verses":{"1":{"text":"By night on my bed I sought him whom my soul loveth: I sought him, but I found him not.","ref":"Song of Solomon 3:1","synthesized":"By night on my bed I sought him whom my soul loveth: I sought him, but I found him not.","sources":{"KJV":{"text":"By night on my bed I sought him whom my soul loveth: I sought him, but I found him not."}},"definableWords":["night","soul"],"peopleInVerse":[]},"2":{"text":"I will rise now, and go about the city in the streets, and in the broad ways I will seek him whom my soul loveth: I sought him, but I found him not.","ref":"Song of Solomon 3:2","synthesized":"I will rise now, and go about the city in the streets, and in the broad ways I will seek him whom my soul loveth: I sought him, but I found him not.","sources":{"KJV":{"text":"I will rise now, and go about the city in the streets, and in the broad ways I will seek him whom my soul loveth: I sought him, but I found him not."}},"definableWords":["soul"],"peopleInVerse":[]},"3":{"text":"The watchmen that go about the city found me: to whom I said, Saw ye him whom my soul loveth?","ref":"Song of Solomon 3:3","synthesized":"The watchmen that go about the city found me: to whom I said, Saw ye him whom my soul loveth?","sources":{"KJV":{"text":"The watchmen that go about the city found me: to whom I said, Saw ye him whom my soul loveth?"}},"definableWords":["saw","soul"],"peopleInVerse":[]},"4":{"text":"It was but a little that I passed from them, but I found him whom my soul loveth: I held him, and would not let him go, until I had brought him into my mother’s house, and into the chamber of her that conceived me.","ref":"Song of Solomon 3:4","synthesized":"It was but a little that I passed from them, but I found him whom my soul loveth: I held him, and would not let him go, until I had brought him into my mother’s house, and into the chamber of her that conceived me.","sources":{"KJV":{"text":"It was but a little that I passed from them, but I found him whom my soul loveth: I held him, and would not let him go, until I had brought him into my mother’s house, and into the chamber of her that conceived me."}},"definableWords":["soul","mother","house"],"peopleInVerse":[]},"5":{"text":"I charge you, O ye daughters of Jerusalem, by the roes, and by the hinds of the field, that ye stir not up, nor awake my love, till he please.","ref":"Song of Solomon 3:5","synthesized":"I charge you, O ye daughters of Jerusalem, by the roes, and by the hinds of the field, that ye stir not up, nor awake my love, till he please.","sources":{"KJV":{"text":"I charge you, O ye daughters of Jerusalem, by the roes, and by the hinds of the field, that ye stir not up, nor awake my love, till he please."}},"definableWords":["charge","daughters","field","love","till"],"peopleInVerse":[]},"6":{"text":"Who is this that cometh out of the wilderness like pillars of smoke, perfumed with myrrh and frankincense, with all powders of the merchant?","ref":"Song of Solomon 3:6","synthesized":"Who is this that cometh out of the wilderness like pillars of smoke, perfumed with myrrh and frankincense, with all powders of the merchant?","sources":{"KJV":{"text":"Who is this that cometh out of the wilderness like pillars of smoke, perfumed with myrrh and frankincense, with all powders of the merchant?"}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"Behold his bed, which is Solomon’s; threescore valiant men are about it, of the valiant of Israel.","ref":"Song of Solomon 3:7","synthesized":"Behold his bed, which is Solomon’s; threescore valiant men are about it, of the valiant of Israel.","sources":{"KJV":{"text":"Behold his bed, which is Solomon’s; threescore valiant men are about it, of the valiant of Israel."}},"definableWords":["men","Israel"],"peopleInVerse":["Solomon"]},"8":{"text":"They all hold swords, being expert in war: every man hath his sword upon his thigh because of fear in the night.","ref":"Song of Solomon 3:8","synthesized":"They all hold swords, being expert in war: every man hath his sword upon his thigh because of fear in the night.","sources":{"KJV":{"text":"They all hold swords, being expert in war: every man hath his sword upon his thigh because of fear in the night."}},"definableWords":["man","fear","night"],"peopleInVerse":[]},"9":{"text":"King Solomon made himself a chariot of the wood of Lebanon.","ref":"Song of Solomon 3:9","synthesized":"King Solomon made himself a chariot of the wood of Lebanon.","sources":{"KJV":{"text":"King Solomon made himself a chariot of the wood of Lebanon."}},"definableWords":["King","made"],"peopleInVerse":["Solomon"]},"10":{"text":"He made the pillars thereof of silver, the bottom thereof of gold, the covering of it of purple, the midst thereof being paved with love, for the daughters of Jerusalem.","ref":"Song of Solomon 3:10","synthesized":"He made the pillars thereof of silver, the bottom thereof of gold, the covering of it of purple, the midst thereof being paved with love, for the daughters of Jerusalem.","sources":{"KJV":{"text":"He made the pillars thereof of silver, the bottom thereof of gold, the covering of it of purple, the midst thereof being paved with love, for the daughters of Jerusalem."}},"definableWords":["made","love","daughters"],"peopleInVerse":[]},"11":{"text":"Go forth, O ye daughters of Zion, and behold king Solomon with the crown wherewith his mother crowned him in the day of his espousals, and in the day of the gladness of his heart.","ref":"Song of Solomon 3:11","synthesized":"Go forth, O ye daughters of Zion, and behold king Solomon with the crown wherewith his mother crowned him in the day of his espousals, and in the day of the gladness of his heart.","sources":{"KJV":{"text":"Go forth, O ye daughters of Zion, and behold king Solomon with the crown wherewith his mother crowned him in the day of his espousals, and in the day of the gladness of his heart."}},"definableWords":["daughters","king","crown","mother","day"],"peopleInVerse":["Solomon"]}}},"4":{"chapter":"4","title":"Song of Solomon 4","verses":{"1":{"text":"Behold, thou art fair, my love; behold, thou art fair; thou hast doves’ eyes within thy locks: thy hair is as a flock of goats, that appear from mount Gilead.","ref":"Song of Solomon 4:1","synthesized":"Behold, thou art fair, my love; behold, thou art fair; thou hast doves’ eyes within thy locks: thy hair is as a flock of goats, that appear from mount Gilead.","sources":{"KJV":{"text":"Behold, thou art fair, my love; behold, thou art fair; thou hast doves’ eyes within thy locks: thy hair is as a flock of goats, that appear from mount Gilead."}},"definableWords":["love"],"peopleInVerse":[]},"2":{"text":"Thy teeth are like a flock of sheep that are even shorn, which came up from the washing; whereof every one bear twins, and none is barren among them.","ref":"Song of Solomon 4:2","synthesized":"Thy teeth are like a flock of sheep that are even shorn, which came up from the washing; whereof every one bear twins, and none is barren among them.","sources":{"KJV":{"text":"Thy teeth are like a flock of sheep that are even shorn, which came up from the washing; whereof every one bear twins, and none is barren among them."}},"definableWords":["one"],"peopleInVerse":[]},"3":{"text":"Thy lips are like a thread of scarlet, and thy speech is comely: thy temples are like a piece of a pomegranate within thy locks.","ref":"Song of Solomon 4:3","synthesized":"Thy lips are like a thread of scarlet, and thy speech is comely: thy temples are like a piece of a pomegranate within thy locks.","sources":{"KJV":{"text":"Thy lips are like a thread of scarlet, and thy speech is comely: thy temples are like a piece of a pomegranate within thy locks."}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"Thy neck is like the tower of David builded for an armoury, whereon there hang a thousand bucklers, all shields of mighty men.","ref":"Song of Solomon 4:4","synthesized":"Thy neck is like the tower of David builded for an armoury, whereon there hang a thousand bucklers, all shields of mighty men.","sources":{"KJV":{"text":"Thy neck is like the tower of David builded for an armoury, whereon there hang a thousand bucklers, all shields of mighty men."}},"definableWords":["mighty","men"],"peopleInVerse":["David"]},"5":{"text":"Thy two breasts are like two young roes that are twins, which feed among the lilies.","ref":"Song of Solomon 4:5","synthesized":"Thy two breasts are like two young roes that are twins, which feed among the lilies.","sources":{"KJV":{"text":"Thy two breasts are like two young roes that are twins, which feed among the lilies."}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"Until the day break, and the shadows flee away, I will get me to the mountain of myrrh, and to the hill of frankincense.","ref":"Song of Solomon 4:6","synthesized":"Until the day break, and the shadows flee away, I will get me to the mountain of myrrh, and to the hill of frankincense.","sources":{"KJV":{"text":"Until the day break, and the shadows flee away, I will get me to the mountain of myrrh, and to the hill of frankincense."}},"definableWords":["day"],"peopleInVerse":[]},"7":{"text":"Thou art all fair, my love; there is no spot in thee.","ref":"Song of Solomon 4:7","synthesized":"Thou art all fair, my love; there is no spot in thee.","sources":{"KJV":{"text":"Thou art all fair, my love; there is no spot in thee."}},"definableWords":["love"],"peopleInVerse":[]},"8":{"text":"Come with me from Lebanon, my spouse, with me from Lebanon: look from the top of Amana, from the top of Shenir and Hermon, from the lions’ dens, from the mountains of the leopards.","ref":"Song of Solomon 4:8","synthesized":"Come with me from Lebanon, my spouse, with me from Lebanon: look from the top of Amana, from the top of Shenir and Hermon, from the lions’ dens, from the mountains of the leopards.","sources":{"KJV":{"text":"Come with me from Lebanon, my spouse, with me from Lebanon: look from the top of Amana, from the top of Shenir and Hermon, from the lions’ dens, from the mountains of the leopards."}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"Thou hast ravished my heart, my sister, my spouse; thou hast ravished my heart with one of thine eyes, with one chain of thy neck.","ref":"Song of Solomon 4:9","synthesized":"Thou hast ravished my heart, my sister, my spouse; thou hast ravished my heart with one of thine eyes, with one chain of thy neck.","sources":{"KJV":{"text":"Thou hast ravished my heart, my sister, my spouse; thou hast ravished my heart with one of thine eyes, with one chain of thy neck."}},"definableWords":["sister","one"],"peopleInVerse":[]},"10":{"text":"How fair is thy love, my sister, my spouse! how much better is thy love than wine! and the smell of thine ointments than all spices!","ref":"Song of Solomon 4:10","synthesized":"How fair is thy love, my sister, my spouse! how much better is thy love than wine! and the smell of thine ointments than all spices!","sources":{"KJV":{"text":"How fair is thy love, my sister, my spouse! how much better is thy love than wine! and the smell of thine ointments than all spices!"}},"definableWords":["love","sister"],"peopleInVerse":[]},"11":{"text":"Thy lips, O my spouse, drop as the honeycomb: honey and milk are under thy tongue; and the smell of thy garments is like the smell of Lebanon.","ref":"Song of Solomon 4:11","synthesized":"Thy lips, O my spouse, drop as the honeycomb: honey and milk are under thy tongue; and the smell of thy garments is like the smell of Lebanon.","sources":{"KJV":{"text":"Thy lips, O my spouse, drop as the honeycomb: honey and milk are under thy tongue; and the smell of thy garments is like the smell of Lebanon."}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"A garden inclosed is my sister, my spouse; a spring shut up, a fountain sealed.","ref":"Song of Solomon 4:12","synthesized":"A garden inclosed is my sister, my spouse; a spring shut up, a fountain sealed.","sources":{"KJV":{"text":"A garden inclosed is my sister, my spouse; a spring shut up, a fountain sealed."}},"definableWords":["garden","sister"],"peopleInVerse":[]},"13":{"text":"Thy plants are an orchard of pomegranates, with pleasant fruits; camphire, with spikenard,","ref":"Song of Solomon 4:13","synthesized":"Thy plants are an orchard of pomegranates, with pleasant fruits; camphire, with spikenard,","sources":{"KJV":{"text":"Thy plants are an orchard of pomegranates, with pleasant fruits; camphire, with spikenard,"}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"Spikenard and saffron; calamus and cinnamon, with all trees of frankincense; myrrh and aloes, with all the chief spices:","ref":"Song of Solomon 4:14","synthesized":"Spikenard and saffron; calamus and cinnamon, with all trees of frankincense; myrrh and aloes, with all the chief spices:","sources":{"KJV":{"text":"Spikenard and saffron; calamus and cinnamon, with all trees of frankincense; myrrh and aloes, with all the chief spices:"}},"definableWords":["trees"],"peopleInVerse":[]},"15":{"text":"A fountain of gardens, a well of living waters, and streams from Lebanon.","ref":"Song of Solomon 4:15","synthesized":"A fountain of gardens, a well of living waters, and streams from Lebanon.","sources":{"KJV":{"text":"A fountain of gardens, a well of living waters, and streams from Lebanon."}},"definableWords":["living","waters"],"peopleInVerse":[]},"16":{"text":"Awake, O north wind; and come, thou south; blow upon my garden, that the spices thereof may flow out. Let my beloved come into his garden, and eat his pleasant fruits.","ref":"Song of Solomon 4:16","synthesized":"Awake, O north wind; and come, thou south; blow upon my garden, that the spices thereof may flow out. Let my beloved come into his garden, and eat his pleasant fruits.","sources":{"KJV":{"text":"Awake, O north wind; and come, thou south; blow upon my garden, that the spices thereof may flow out. Let my beloved come into his garden, and eat his pleasant fruits."}},"definableWords":["garden"],"peopleInVerse":[]}}},"5":{"chapter":"5","title":"Song of Solomon 5","verses":{"1":{"text":"I am come into my garden, my sister, my spouse: I have gathered my myrrh with my spice; I have eaten my honeycomb with my honey; I have drunk my wine with my milk: eat, O friends; drink, yea, drink abundantly, O beloved.","ref":"Song of Solomon 5:1","synthesized":"I am come into my garden, my sister, my spouse: I have gathered my myrrh with my spice; I have eaten my honeycomb with my honey; I have drunk my wine with my milk: eat, O friends; drink, yea, drink abundantly, O beloved.","sources":{"KJV":{"text":"I am come into my garden, my sister, my spouse: I have gathered my myrrh with my spice; I have eaten my honeycomb with my honey; I have drunk my wine with my milk: eat, O friends; drink, yea, drink abundantly, O beloved."}},"definableWords":["garden","sister"],"peopleInVerse":[]},"2":{"text":"I sleep, but my heart waketh: it is the voice of my beloved that knocketh, saying, Open to me, my sister, my love, my dove, my undefiled: for my head is filled with dew, and my locks with the drops of the night.","ref":"Song of Solomon 5:2","synthesized":"I sleep, but my heart waketh: it is the voice of my beloved that knocketh, saying, Open to me, my sister, my love, my dove, my undefiled: for my head is filled with dew, and my locks with the drops of the night.","sources":{"KJV":{"text":"I sleep, but my heart waketh: it is the voice of my beloved that knocketh, saying, Open to me, my sister, my love, my dove, my undefiled: for my head is filled with dew, and my locks with the drops of the night."}},"definableWords":["voice","sister","love","night"],"peopleInVerse":[]},"3":{"text":"I have put off my coat; how shall I put it on? I have washed my feet; how shall I defile them?","ref":"Song of Solomon 5:3","synthesized":"I have put off my coat; how shall I put it on? I have washed my feet; how shall I defile them?","sources":{"KJV":{"text":"I have put off my coat; how shall I put it on? I have washed my feet; how shall I defile them?"}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"My beloved put in his hand by the hole of the door, and my bowels were moved for him.","ref":"Song of Solomon 5:4","synthesized":"My beloved put in his hand by the hole of the door, and my bowels were moved for him.","sources":{"KJV":{"text":"My beloved put in his hand by the hole of the door, and my bowels were moved for him."}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"I rose up to open to my beloved; and my hands dropped with myrrh, and my fingers with sweet smelling myrrh, upon the handles of the lock.","ref":"Song of Solomon 5:5","synthesized":"I rose up to open to my beloved; and my hands dropped with myrrh, and my fingers with sweet smelling myrrh, upon the handles of the lock.","sources":{"KJV":{"text":"I rose up to open to my beloved; and my hands dropped with myrrh, and my fingers with sweet smelling myrrh, upon the handles of the lock."}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"I opened to my beloved; but my beloved had withdrawn himself, and was gone: my soul failed when he spake: I sought him, but I could not find him; I called him, but he gave me no answer.","ref":"Song of Solomon 5:6","synthesized":"I opened to my beloved; but my beloved had withdrawn himself, and was gone: my soul failed when he spake: I sought him, but I could not find him; I called him, but he gave me no answer.","sources":{"KJV":{"text":"I opened to my beloved; but my beloved had withdrawn himself, and was gone: my soul failed when he spake: I sought him, but I could not find him; I called him, but he gave me no answer."}},"definableWords":["soul"],"peopleInVerse":[]},"7":{"text":"The watchmen that went about the city found me, they smote me, they wounded me; the keepers of the walls took away my veil from me.","ref":"Song of Solomon 5:7","synthesized":"The watchmen that went about the city found me, they smote me, they wounded me; the keepers of the walls took away my veil from me.","sources":{"KJV":{"text":"The watchmen that went about the city found me, they smote me, they wounded me; the keepers of the walls took away my veil from me."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"I charge you, O daughters of Jerusalem, if ye find my beloved, that ye tell him, that I am sick of love.","ref":"Song of Solomon 5:8","synthesized":"I charge you, O daughters of Jerusalem, if ye find my beloved, that ye tell him, that I am sick of love.","sources":{"KJV":{"text":"I charge you, O daughters of Jerusalem, if ye find my beloved, that ye tell him, that I am sick of love."}},"definableWords":["charge","daughters","love"],"peopleInVerse":[]},"9":{"text":"What is thy beloved more than another beloved, O thou fairest among women? what is thy beloved more than another beloved, that thou dost so charge us?","ref":"Song of Solomon 5:9","synthesized":"What is thy beloved more than another beloved, O thou fairest among women? what is thy beloved more than another beloved, that thou dost so charge us?","sources":{"KJV":{"text":"What is thy beloved more than another beloved, O thou fairest among women? what is thy beloved more than another beloved, that thou dost so charge us?"}},"definableWords":["women","charge"],"peopleInVerse":[]},"10":{"text":"My beloved is white and ruddy, the chiefest among ten thousand.","ref":"Song of Solomon 5:10","synthesized":"My beloved is white and ruddy, the chiefest among ten thousand.","sources":{"KJV":{"text":"My beloved is white and ruddy, the chiefest among ten thousand."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"His head is as the most fine gold, his locks are bushy, and black as a raven.","ref":"Song of Solomon 5:11","synthesized":"His head is as the most fine gold, his locks are bushy, and black as a raven.","sources":{"KJV":{"text":"His head is as the most fine gold, his locks are bushy, and black as a raven."}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"His eyes are as the eyes of doves by the rivers of waters, washed with milk, and fitly set.","ref":"Song of Solomon 5:12","synthesized":"His eyes are as the eyes of doves by the rivers of waters, washed with milk, and fitly set.","sources":{"KJV":{"text":"His eyes are as the eyes of doves by the rivers of waters, washed with milk, and fitly set."}},"definableWords":["waters"],"peopleInVerse":[]},"13":{"text":"His cheeks are as a bed of spices, as sweet flowers: his lips like lilies, dropping sweet smelling myrrh.","ref":"Song of Solomon 5:13","synthesized":"His cheeks are as a bed of spices, as sweet flowers: his lips like lilies, dropping sweet smelling myrrh.","sources":{"KJV":{"text":"His cheeks are as a bed of spices, as sweet flowers: his lips like lilies, dropping sweet smelling myrrh."}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"His hands are as gold rings set with the beryl: his belly is as bright ivory overlaid with sapphires.","ref":"Song of Solomon 5:14","synthesized":"His hands are as gold rings set with the beryl: his belly is as bright ivory overlaid with sapphires.","sources":{"KJV":{"text":"His hands are as gold rings set with the beryl: his belly is as bright ivory overlaid with sapphires."}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"His legs are as pillars of marble, set upon sockets of fine gold: his countenance is as Lebanon, excellent as the cedars.","ref":"Song of Solomon 5:15","synthesized":"His legs are as pillars of marble, set upon sockets of fine gold: his countenance is as Lebanon, excellent as the cedars.","sources":{"KJV":{"text":"His legs are as pillars of marble, set upon sockets of fine gold: his countenance is as Lebanon, excellent as the cedars."}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"His mouth is most sweet: yea, he is altogether lovely. This is my beloved, and this is my friend, O daughters of Jerusalem.","ref":"Song of Solomon 5:16","synthesized":"His mouth is most sweet: yea, he is altogether lovely. This is my beloved, and this is my friend, O daughters of Jerusalem.","sources":{"KJV":{"text":"His mouth is most sweet: yea, he is altogether lovely. This is my beloved, and this is my friend, O daughters of Jerusalem."}},"definableWords":["daughters"],"peopleInVerse":[]}}},"6":{"chapter":"6","title":"Song of Solomon 6","verses":{"1":{"text":"Whither is thy beloved gone, O thou fairest among women? whither is thy beloved turned aside? that we may seek him with thee.","ref":"Song of Solomon 6:1","synthesized":"Whither is thy beloved gone, O thou fairest among women? whither is thy beloved turned aside? that we may seek him with thee.","sources":{"KJV":{"text":"Whither is thy beloved gone, O thou fairest among women? whither is thy beloved turned aside? that we may seek him with thee."}},"definableWords":["women"],"peopleInVerse":[]},"2":{"text":"My beloved is gone down into his garden, to the beds of spices, to feed in the gardens, and to gather lilies.","ref":"Song of Solomon 6:2","synthesized":"My beloved is gone down into his garden, to the beds of spices, to feed in the gardens, and to gather lilies.","sources":{"KJV":{"text":"My beloved is gone down into his garden, to the beds of spices, to feed in the gardens, and to gather lilies."}},"definableWords":["garden"],"peopleInVerse":[]},"3":{"text":"I am my beloved’s, and my beloved is mine: he feedeth among the lilies.","ref":"Song of Solomon 6:3","synthesized":"I am my beloved’s, and my beloved is mine: he feedeth among the lilies.","sources":{"KJV":{"text":"I am my beloved’s, and my beloved is mine: he feedeth among the lilies."}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"Thou art beautiful, O my love, as Tirzah, comely as Jerusalem, terrible as an army with banners.","ref":"Song of Solomon 6:4","synthesized":"Thou art beautiful, O my love, as Tirzah, comely as Jerusalem, terrible as an army with banners.","sources":{"KJV":{"text":"Thou art beautiful, O my love, as Tirzah, comely as Jerusalem, terrible as an army with banners."}},"definableWords":["love"],"peopleInVerse":[]},"5":{"text":"Turn away thine eyes from me, for they have overcome me: thy hair is as a flock of goats that appear from Gilead.","ref":"Song of Solomon 6:5","synthesized":"Turn away thine eyes from me, for they have overcome me: thy hair is as a flock of goats that appear from Gilead.","sources":{"KJV":{"text":"Turn away thine eyes from me, for they have overcome me: thy hair is as a flock of goats that appear from Gilead."}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"Thy teeth are as a flock of sheep which go up from the washing, whereof every one beareth twins, and there is not one barren among them.","ref":"Song of Solomon 6:6","synthesized":"Thy teeth are as a flock of sheep which go up from the washing, whereof every one beareth twins, and there is not one barren among them.","sources":{"KJV":{"text":"Thy teeth are as a flock of sheep which go up from the washing, whereof every one beareth twins, and there is not one barren among them."}},"definableWords":["one"],"peopleInVerse":[]},"7":{"text":"As a piece of a pomegranate are thy temples within thy locks.","ref":"Song of Solomon 6:7","synthesized":"As a piece of a pomegranate are thy temples within thy locks.","sources":{"KJV":{"text":"As a piece of a pomegranate are thy temples within thy locks."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"There are threescore queens, and fourscore concubines, and virgins without number.","ref":"Song of Solomon 6:8","synthesized":"There are threescore queens, and fourscore concubines, and virgins without number.","sources":{"KJV":{"text":"There are threescore queens, and fourscore concubines, and virgins without number."}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"My dove, my undefiled is but one; she is the only one of her mother, she is the choice one of her that bare her. The daughters saw her, and blessed her; yea, the queens and the concubines, and they praised her.","ref":"Song of Solomon 6:9","synthesized":"My dove, my undefiled is but one; she is the only one of her mother, she is the choice one of her that bare her. The daughters saw her, and blessed her; yea, the queens and the concubines, and they praised her.","sources":{"KJV":{"text":"My dove, my undefiled is but one; she is the only one of her mother, she is the choice one of her that bare her. The daughters saw her, and blessed her; yea, the queens and the concubines, and they praised her."}},"definableWords":["one","mother","daughters","saw","blessed"],"peopleInVerse":[]},"10":{"text":"Who is she that looketh forth as the morning, fair as the moon, clear as the sun, and terrible as an army with banners?","ref":"Song of Solomon 6:10","synthesized":"Who is she that looketh forth as the morning, fair as the moon, clear as the sun, and terrible as an army with banners?","sources":{"KJV":{"text":"Who is she that looketh forth as the morning, fair as the moon, clear as the sun, and terrible as an army with banners?"}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"I went down into the garden of nuts to see the fruits of the valley, and to see whether the vine flourished, and the pomegranates budded.","ref":"Song of Solomon 6:11","synthesized":"I went down into the garden of nuts to see the fruits of the valley, and to see whether the vine flourished, and the pomegranates budded.","sources":{"KJV":{"text":"I went down into the garden of nuts to see the fruits of the valley, and to see whether the vine flourished, and the pomegranates budded."}},"definableWords":["garden","see"],"peopleInVerse":[]},"12":{"text":"Or ever I was aware, my soul made me like the chariots of Amminadib.","ref":"Song of Solomon 6:12","synthesized":"Or ever I was aware, my soul made me like the chariots of Amminadib.","sources":{"KJV":{"text":"Or ever I was aware, my soul made me like the chariots of Amminadib."}},"definableWords":["or","soul","made"],"peopleInVerse":[]},"13":{"text":"Return, return, O Shulamite; return, return, that we may look upon thee. What will ye see in the Shulamite? As it were the company of two armies.","ref":"Song of Solomon 6:13","synthesized":"Return, return, O Shulamite; return, return, that we may look upon thee. What will ye see in the Shulamite? As it were the company of two armies.","sources":{"KJV":{"text":"Return, return, O Shulamite; return, return, that we may look upon thee. What will ye see in the Shulamite? As it were the company of two armies."}},"definableWords":["see"],"peopleInVerse":[]}}},"7":{"chapter":"7","title":"Song of Solomon 7","verses":{"1":{"text":"How beautiful are thy feet with shoes, O prince’s daughter! the joints of thy thighs are like jewels, the work of the hands of a cunning workman.","ref":"Song of Solomon 7:1","synthesized":"How beautiful are thy feet with shoes, O prince’s daughter! the joints of thy thighs are like jewels, the work of the hands of a cunning workman.","sources":{"KJV":{"text":"How beautiful are thy feet with shoes, O prince’s daughter! the joints of thy thighs are like jewels, the work of the hands of a cunning workman."}},"definableWords":["prince","daughter","work"],"peopleInVerse":[]},"2":{"text":"Thy navel is like a round goblet, which wanteth not liquor: thy belly is like an heap of wheat set about with lilies.","ref":"Song of Solomon 7:2","synthesized":"Thy navel is like a round goblet, which wanteth not liquor: thy belly is like an heap of wheat set about with lilies.","sources":{"KJV":{"text":"Thy navel is like a round goblet, which wanteth not liquor: thy belly is like an heap of wheat set about with lilies."}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"Thy two breasts are like two young roes that are twins.","ref":"Song of Solomon 7:3","synthesized":"Thy two breasts are like two young roes that are twins.","sources":{"KJV":{"text":"Thy two breasts are like two young roes that are twins."}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"Thy neck is as a tower of ivory; thine eyes like the fishpools in Heshbon, by the gate of Bathrabbim: thy nose is as the tower of Lebanon which looketh toward Damascus.","ref":"Song of Solomon 7:4","synthesized":"Thy neck is as a tower of ivory; thine eyes like the fishpools in Heshbon, by the gate of Bathrabbim: thy nose is as the tower of Lebanon which looketh toward Damascus.","sources":{"KJV":{"text":"Thy neck is as a tower of ivory; thine eyes like the fishpools in Heshbon, by the gate of Bathrabbim: thy nose is as the tower of Lebanon which looketh toward Damascus."}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"Thine head upon thee is like Carmel, and the hair of thine head like purple; the king is held in the galleries.","ref":"Song of Solomon 7:5","synthesized":"Thine head upon thee is like Carmel, and the hair of thine head like purple; the king is held in the galleries.","sources":{"KJV":{"text":"Thine head upon thee is like Carmel, and the hair of thine head like purple; the king is held in the galleries."}},"definableWords":["king"],"peopleInVerse":[]},"6":{"text":"How fair and how pleasant art thou, O love, for delights!","ref":"Song of Solomon 7:6","synthesized":"How fair and how pleasant art thou, O love, for delights!","sources":{"KJV":{"text":"How fair and how pleasant art thou, O love, for delights!"}},"definableWords":["love"],"peopleInVerse":[]},"7":{"text":"This thy stature is like to a palm tree, and thy breasts to clusters of grapes.","ref":"Song of Solomon 7:7","synthesized":"This thy stature is like to a palm tree, and thy breasts to clusters of grapes.","sources":{"KJV":{"text":"This thy stature is like to a palm tree, and thy breasts to clusters of grapes."}},"definableWords":["tree"],"peopleInVerse":[]},"8":{"text":"I said, I will go up to the palm tree, I will take hold of the boughs thereof: now also thy breasts shall be as clusters of the vine, and the smell of thy nose like apples;","ref":"Song of Solomon 7:8","synthesized":"I said, I will go up to the palm tree, I will take hold of the boughs thereof: now also thy breasts shall be as clusters of the vine, and the smell of thy nose like apples;","sources":{"KJV":{"text":"I said, I will go up to the palm tree, I will take hold of the boughs thereof: now also thy breasts shall be as clusters of the vine, and the smell of thy nose like apples;"}},"definableWords":["tree"],"peopleInVerse":[]},"9":{"text":"And the roof of thy mouth like the best wine for my beloved, that goeth down sweetly, causing the lips of those that are asleep to speak.","ref":"Song of Solomon 7:9","synthesized":"And the roof of thy mouth like the best wine for my beloved, that goeth down sweetly, causing the lips of those that are asleep to speak.","sources":{"KJV":{"text":"And the roof of thy mouth like the best wine for my beloved, that goeth down sweetly, causing the lips of those that are asleep to speak."}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"I am my beloved’s, and his desire is toward me.","ref":"Song of Solomon 7:10","synthesized":"I am my beloved’s, and his desire is toward me.","sources":{"KJV":{"text":"I am my beloved’s, and his desire is toward me."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"Come, my beloved, let us go forth into the field; let us lodge in the villages.","ref":"Song of Solomon 7:11","synthesized":"Come, my beloved, let us go forth into the field; let us lodge in the villages.","sources":{"KJV":{"text":"Come, my beloved, let us go forth into the field; let us lodge in the villages."}},"definableWords":["field"],"peopleInVerse":[]},"12":{"text":"Let us get up early to the vineyards; let us see if the vine flourish, whether the tender grape appear, and the pomegranates bud forth: there will I give thee my loves.","ref":"Song of Solomon 7:12","synthesized":"Let us get up early to the vineyards; let us see if the vine flourish, whether the tender grape appear, and the pomegranates bud forth: there will I give thee my loves.","sources":{"KJV":{"text":"Let us get up early to the vineyards; let us see if the vine flourish, whether the tender grape appear, and the pomegranates bud forth: there will I give thee my loves."}},"definableWords":["see"],"peopleInVerse":[]},"13":{"text":"The mandrakes give a smell, and at our gates are all manner of pleasant fruits, new and old, which I have laid up for thee, O my beloved.","ref":"Song of Solomon 7:13","synthesized":"The mandrakes give a smell, and at our gates are all manner of pleasant fruits, new and old, which I have laid up for thee, O my beloved.","sources":{"KJV":{"text":"The mandrakes give a smell, and at our gates are all manner of pleasant fruits, new and old, which I have laid up for thee, O my beloved."}},"definableWords":[],"peopleInVerse":[]}}},"8":{"chapter":"8","title":"Song of Solomon 8","verses":{"1":{"text":"O that thou wert as my brother, that sucked the breasts of my mother! when I should find thee without, I would kiss thee; yea, I should not be despised.","ref":"Song of Solomon 8:1","synthesized":"O that thou wert as my brother, that sucked the breasts of my mother! when I should find thee without, I would kiss thee; yea, I should not be despised.","sources":{"KJV":{"text":"O that thou wert as my brother, that sucked the breasts of my mother! when I should find thee without, I would kiss thee; yea, I should not be despised."}},"definableWords":["brother","mother"],"peopleInVerse":[]},"2":{"text":"I would lead thee, and bring thee into my mother’s house, who would instruct me: I would cause thee to drink of spiced wine of the juice of my pomegranate.","ref":"Song of Solomon 8:2","synthesized":"I would lead thee, and bring thee into my mother’s house, who would instruct me: I would cause thee to drink of spiced wine of the juice of my pomegranate.","sources":{"KJV":{"text":"I would lead thee, and bring thee into my mother’s house, who would instruct me: I would cause thee to drink of spiced wine of the juice of my pomegranate."}},"definableWords":["mother","house"],"peopleInVerse":[]},"3":{"text":"His left hand should be under my head, and his right hand should embrace me.","ref":"Song of Solomon 8:3","synthesized":"His left hand should be under my head, and his right hand should embrace me.","sources":{"KJV":{"text":"His left hand should be under my head, and his right hand should embrace me."}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"I charge you, O daughters of Jerusalem, that ye stir not up, nor awake my love, until he please.","ref":"Song of Solomon 8:4","synthesized":"I charge you, O daughters of Jerusalem, that ye stir not up, nor awake my love, until he please.","sources":{"KJV":{"text":"I charge you, O daughters of Jerusalem, that ye stir not up, nor awake my love, until he please."}},"definableWords":["charge","daughters","love"],"peopleInVerse":[]},"5":{"text":"Who is this that cometh up from the wilderness, leaning upon her beloved? I raised thee up under the apple tree: there thy mother brought thee forth: there she brought thee forth that bare thee.","ref":"Song of Solomon 8:5","synthesized":"Who is this that cometh up from the wilderness, leaning upon her beloved? I raised thee up under the apple tree: there thy mother brought thee forth: there she brought thee forth that bare thee.","sources":{"KJV":{"text":"Who is this that cometh up from the wilderness, leaning upon her beloved? I raised thee up under the apple tree: there thy mother brought thee forth: there she brought thee forth that bare thee."}},"definableWords":["tree","mother"],"peopleInVerse":[]},"6":{"text":"Set me as a seal upon thine heart, as a seal upon thine arm: for love is strong as death; jealousy is cruel as the grave: the coals thereof are coals of fire, which hath a most vehement flame.","ref":"Song of Solomon 8:6","synthesized":"Set me as a seal upon thine heart, as a seal upon thine arm: for love is strong as death; jealousy is cruel as the grave: the coals thereof are coals of fire, which hath a most vehement flame.","sources":{"KJV":{"text":"Set me as a seal upon thine heart, as a seal upon thine arm: for love is strong as death; jealousy is cruel as the grave: the coals thereof are coals of fire, which hath a most vehement flame."}},"definableWords":["love","strong","death"],"peopleInVerse":[]},"7":{"text":"Many waters cannot quench love, neither can the floods drown it: if a man would give all the substance of his house for love, it would utterly be contemned.","ref":"Song of Solomon 8:7","synthesized":"Many waters cannot quench love, neither can the floods drown it: if a man would give all the substance of his house for love, it would utterly be contemned.","sources":{"KJV":{"text":"Many waters cannot quench love, neither can the floods drown it: if a man would give all the substance of his house for love, it would utterly be contemned."}},"definableWords":["waters","love","man","house"],"peopleInVerse":[]},"8":{"text":"We have a little sister, and she hath no breasts: what shall we do for our sister in the day when she shall be spoken for?","ref":"Song of Solomon 8:8","synthesized":"We have a little sister, and she hath no breasts: what shall we do for our sister in the day when she shall be spoken for?","sources":{"KJV":{"text":"We have a little sister, and she hath no breasts: what shall we do for our sister in the day when she shall be spoken for?"}},"definableWords":["sister","day"],"peopleInVerse":[]},"9":{"text":"If she be a wall, we will build upon her a palace of silver: and if she be a door, we will inclose her with boards of cedar.","ref":"Song of Solomon 8:9","synthesized":"If she be a wall, we will build upon her a palace of silver: and if she be a door, we will inclose her with boards of cedar.","sources":{"KJV":{"text":"If she be a wall, we will build upon her a palace of silver: and if she be a door, we will inclose her with boards of cedar."}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"I am a wall, and my breasts like towers: then was I in his eyes as one that found favour.","ref":"Song of Solomon 8:10","synthesized":"I am a wall, and my breasts like towers: then was I in his eyes as one that found favour.","sources":{"KJV":{"text":"I am a wall, and my breasts like towers: then was I in his eyes as one that found favour."}},"definableWords":["one"],"peopleInVerse":[]},"11":{"text":"Solomon had a vineyard at Baalhamon; he let out the vineyard unto keepers; every one for the fruit thereof was to bring a thousand pieces of silver.","ref":"Song of Solomon 8:11","synthesized":"Solomon had a vineyard at Baalhamon; he let out the vineyard unto keepers; every one for the fruit thereof was to bring a thousand pieces of silver.","sources":{"KJV":{"text":"Solomon had a vineyard at Baalhamon; he let out the vineyard unto keepers; every one for the fruit thereof was to bring a thousand pieces of silver."}},"definableWords":["one"],"peopleInVerse":["Solomon"]},"12":{"text":"My vineyard, which is mine, is before me: thou, O Solomon, must have a thousand, and those that keep the fruit thereof two hundred.","ref":"Song of Solomon 8:12","synthesized":"My vineyard, which is mine, is before me: thou, O Solomon, must have a thousand, and those that keep the fruit thereof two hundred.","sources":{"KJV":{"text":"My vineyard, which is mine, is before me: thou, O Solomon, must have a thousand, and those that keep the fruit thereof two hundred."}},"definableWords":["keep"],"peopleInVerse":["Solomon"]},"13":{"text":"Thou that dwellest in the gardens, the companions hearken to thy voice: cause me to hear it.","ref":"Song of Solomon 8:13","synthesized":"Thou that dwellest in the gardens, the companions hearken to thy voice: cause me to hear it.","sources":{"KJV":{"text":"Thou that dwellest in the gardens, the companions hearken to thy voice: cause me to hear it."}},"definableWords":["voice"],"peopleInVerse":[]},"14":{"text":"Make haste, my beloved, and be thou like to a roe or to a young hart upon the mountains of spices.","ref":"Song of Solomon 8:14","synthesized":"Make haste, my beloved, and be thou like to a roe or to a young hart upon the mountains of spices.","sources":{"KJV":{"text":"Make haste, my beloved, and be thou like to a roe or to a young hart upon the mountains of spices."}},"definableWords":["make","or"],"peopleInVerse":[]}}}};